Use ASP.NET Core's `WebApplicationFactory<T>` — it hosts your app in-memory and gives you an `HttpClient` that talks to it without a real network listener.

**Setup:**

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**Example test class:**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (stateful servers need this)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory test server (`TestServer`).
- **Full pipeline** — middleware, DI, routing, and your MCP handler all run as in production.
- **SSE streaming** — if your server uses the SSE transport, read the response stream directly:
  ```csharp
  var response = await _client.GetAsync("/mcp/sse", HttpCompletionOption.ResponseHeadersRead);
  using var stream = await response.Content.ReadAsStreamAsync();
  using var reader = new StreamReader(stream);
  var line = await reader.ReadLineAsync(); // "event: ..." / "data: ..."
  ```
- **Override services** — use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks (e.g., fake databases).

This gives you real HTTP integration tests with zero network overhead.
